  # Explicit per-chain jittered initialisation at prior medians.
  # Used as Pathfinder fallback; safe for ridge-shaped posteriors.
  safe_init &lt;- lapply(seq_len(4), function(i) list(
    alpha = rnorm(1, 0.0, 0.1),
    nu    = rnorm(1, -1.0, 0.1)
  ))

  init_pf &lt;- tryCatch(
    mod_single$pathfinder(
      data      = data,
      seed      = 8,
      num_paths = 4,
      refresh   = 0
    ),
    error = function(e) {
      message("Pathfinder failed — falling back to jittered prior-centre initialisation.")
      safe_init
    }
  )

  fit_single &lt;- mod_single$sample(
    data            = data,
    init            = init_pf,
    seed            = 8,
    chains          = 4,
    parallel_chains = 4,
    iter_warmup     = 1000,
    iter_sampling   = 2000,
