  op_vec    &lt;- rbinom(N, 1, op_bias)
  sim_dat   &lt;- simulate_tom0(op_vec, log_sigma, log_beta, bias)
  list(
    variables = list(log_sigma = log_sigma,
                     log_beta  = log_beta,
                     bias      = bias),
    generated = list(N = N,
                     choice    = sim_dat$choice,
                     op_choice = sim_dat$op_choice)
  )
}

