12.8.1 Stan code: SBA


Code
\usetikzlibrary{bayesnet}
\begin{tikzpicture}
  % Nodes
  \node[const] (alpha0) {$\alpha_0$};
  \node[const, right=1cm of alpha0] (beta0) {$\beta_0$};

  \node[obs, below left=1.5cm and 0.5cm of alpha0] (blue1) {$k_{1,i}$};
  \node[obs, right=0.5cm of blue1] (total1) {$n_{1,i}$};

  \node[obs, below right=1.5cm and 0.5cm of beta0] (blue2) {$k_{2,i}$};
  \node[obs, right=0.5cm of blue2] (total2) {$n_{2,i}$};

  \node[det, below=3.5cm of alpha0] (alphapost) {$\alpha_{post,i}$};
  \node[det, below=3.5cm of beta0] (betapost) {$\beta_{post,i}$};

  \node[obs, below=1.5cm of alphapost, xshift=0.75cm] (choice) {$y_i$};

  % Edges
  \edge {alpha0} {alphapost};
  \edge {beta0} {betapost};
  \edge {blue1, total1, blue2, total2} {alphapost, betapost};
  \edge {alphapost, betapost} {choice};

  % Plate
  \plate {p1} {(blue1)(total1)(blue2)(total2)(alphapost)(betapost)(choice)} {$N$};
\end{tikzpicture}





DAG for the Simple Bayesian Agent




The generative relationships for the SBA are: \[
\begin{aligned}
\alpha_{post,i} &= \alpha_0 + k_{1,i} + k_{2,i} \\
\beta_{post,i}  &= \beta_0 + (n_{1,i} - k_{1,i}) + (n_{2,i} - k_{2,i}) \\
y_i &\sim \text{Beta-Binomial}(1, \alpha_{post,i}, \beta_{post,i})
\end{aligned}
\]


Code
SimpleAgent_stan &lt;- "
// Simple Bayesian Agent (SBA).
// No free parameters — evidence is counted at face value.
// Jeffreys prior pseudo-counts: alpha0 = beta0 = 0.5.
data {
  int&lt;lower=1&gt; N_total;
  array[N_total] int&lt;lower=0, upper=1&gt; y;
  array[N_total] int&lt;lower=0&gt; blue1;
  array[N_total] int&lt;lower=0&gt; total1;
  array[N_total] int&lt;lower=0&gt; blue2;
  array[N_total] int&lt;lower=0&gt; total2;
  int&lt;lower=0, upper=1&gt; run_diagnostics;
}

model {
  // Vectorized likelihood with fixed weights = 1
  vector[N_total] alpha_post = 0.5 + to_vector(blue1) + to_vector(blue2);
  vector[N_total] beta_post  = 0.5 + (to_vector(total1) - to_vector(blue1))
                                   + (to_vector(total2) - to_vector(blue2));

  target += beta_binomial_lpmf(y | 1, alpha_post, beta_post);
}

generated quantities {
  vector[N_total] log_lik;
  array[N_total] int y_rep;

  if (run_diagnostics) {
    for (i in 1:N_total) {
      real alpha_post = 0.5 + blue1[i] + blue2[i];
      real beta_post  = 0.5 + (total1[i] - blue1[i]) + (total2[i] - blue2[i]);

      log_lik[i] = beta_binomial_lpmf(y[i] | 1, alpha_post, beta_post);
      y_rep[i]   = beta_binomial_rng(1, alpha_post, beta_post);
    }
  }
}
"

write_stan_file(SimpleAgent_stan,
                dir      = "stan/",
                basename = "ch10_simple_agent.stan")


