12.8.2 Stan code: WBA (raw parameterisation)
We start with the intuitive parameterisation using \(w_d\) and \(w_s\) directly:


Code
\usetikzlibrary{bayesnet}
\begin{tikzpicture}
  % Fixed Prior
  \node[const] (alpha0) {$\alpha_0$};
  \node[const, right=1.5cm of alpha0] (beta0) {$\beta_0$};

  % Latent Parameters (Direct Weights)
  \node[latent, below=1.2cm of alpha0] (wd) {$w_d$}; 
  \node[latent, below=1.2cm of beta0] (ws) {$w_s$};

  % Inputs
  \node[obs, left=1cm of wd] (k1) {$k_{1,i}$};
  \node[obs, left=0.3cm of k1] (n1) {$n_{1,i}$};
  \node[obs, right=1cm of ws] (k2) {$k_{2,i}$};
  \node[obs, right=0.3cm of k2] (n2) {$n_{2,i}$};

  % Beliefs
  \node[det, below=2.5cm of wd] (ap) {$\alpha_{post,i}$};
  \node[det, below=2.5cm of ws] (bp) {$\beta_{post,i}$};

  % Action
  \node[obs, below=1.2cm of ap, xshift=1.25cm] (y) {$y_i$};

  % Edges
  \edge {alpha0, beta0} {ap, bp};
  \edge {wd, k1, n1, ws, k2, n2} {ap, bp};
  \edge {ap, bp} {y};

  \plate {p1} {(k1)(n1)(k2)(n2)(ap)(bp)(y)} {$N$};
\end{tikzpicture}





DAG for the unreparameterized Weighted Bayesian Agent




The generative relationships for the unreparameterized WBA are: \[
\begin{aligned}
w_d &\sim \text{Lognormal}(0, 0.5) \\
w_s &\sim \text{Lognormal}(0, 0.5) \\
\alpha_{post,i} &= \alpha_0 + w_d k_{1,i} + w_s k_{2,i} \\
\beta_{post,i}  &= \beta_0 + w_d(n_{1,i} - k_{1,i}) + w_s(n_{2,i} - k_{2,i}) \\
y_i &\sim \text{Beta-Binomial}(1, \alpha_{post,i}, \beta_{post,i})
\end{aligned}
\]


Code
WeightedAgentRaw_stan &lt;- "
// Weighted Bayesian Agent (raw parameterisation).
// weight_direct, weight_social &gt; 0: independent weights on direct and social evidence.
// Jeffreys prior pseudo-counts (0.5) consistent with SBA.
data {
  int&lt;lower=1&gt; N_total;
  array[N_total] int&lt;lower=0, upper=1&gt; y;
  array[N_total] int&lt;lower=0&gt; blue1;
  array[N_total] int&lt;lower=0&gt; total1;
  array[N_total] int&lt;lower=0&gt; blue2;
  array[N_total] int&lt;lower=0&gt; total2;

  real prior_wd_mu;
  real&lt;lower=0&gt; prior_wd_sigma;
  real prior_ws_mu;
  real&lt;lower=0&gt; prior_ws_sigma;
  int&lt;lower=0, upper=1&gt; run_diagnostics;
}

parameters {
  real&lt;lower=0&gt; weight_direct;  // w_d
  real&lt;lower=0&gt; weight_social;  // w_s
}

model {
  // Priors: lognormal centered on 1 (evidence taken at face value)
  target += lognormal_lpdf(weight_direct | prior_wd_mu, prior_wd_sigma);
  target += lognormal_lpdf(weight_social | prior_ws_mu, prior_ws_sigma);

  // Vectorized likelihood
  vector[N_total] alpha_post = 0.5 + weight_direct * to_vector(blue1)
                                   + weight_social * to_vector(blue2);
  vector[N_total] beta_post  = 0.5 + weight_direct * (to_vector(total1) - to_vector(blue1))
                                   + weight_social * (to_vector(total2) - to_vector(blue2));

  target += beta_binomial_lpmf(y | 1, alpha_post, beta_post);
}

generated quantities {
  vector[N_total] log_lik;
  array[N_total] int y_rep;

  if (run_diagnostics) {
    for (i in 1:N_total) {
      real alpha_post = 0.5 + weight_direct * blue1[i] + weight_social * blue2[i];
      real beta_post  = 0.5 + weight_direct * (total1[i] - blue1[i]) 
                           + weight_social * (total2[i] - blue2[i]);

      log_lik[i] = beta_binomial_lpmf(y[i] | 1, alpha_post, beta_post);
      y_rep[i]   = beta_binomial_rng(1, alpha_post, beta_post);
    }
  }
}
"

write_stan_file(WeightedAgentRaw_stan,
                dir      = "stan/",
                basename = "ch10_weighted_agent_raw.stan")


