if (regenerate_simulations || !all(file.exists(fit_wba_raw_paths))) {
  seeds &lt;- set_names(101:103, names(stan_data_wba))

  fit_wba_raw &lt;- imap(stan_data_wba, function(data, scenario) {
    fit &lt;- do.call(
      mod_weighted_raw$sample,
      c(list(data = data, seed = seeds[[scenario]]), sampler_args)
    )
    # $save_object() internalises the CSV draws so the file is
    # self-contained. Plain saveRDS() would store dangling pointers
    # to temporary CSVs that no longer exist in a new session.
