}
# Check diagnostics
check_diagnostics &lt;- function(fit, label) {
  diag_smry &lt;- fit$diagnostic_summary()
  min_ebfmi &lt;- min(diag_smry$ebfmi)

  smry &lt;- fit$summary() |&gt; filter(!is.na(rhat))
  n_fail &lt;- smry |&gt; filter(rhat &gt; 1.01 | ess_bulk &lt; 400 | ess_tail &lt; 400) |&gt; nrow()

  cat(sprintf("%-25s | Divs: %3d | Min E-BFMI: %.2f | Failures: %d\n", 
              label, sum(diag_smry$num_divergent), min_ebfmi, n_fail))
}

