  \node[obs, right=0.3cm of blue1] (total1) {$n_{1,i}$};

  \node[obs, below right=1.5cm and 0.5cm of beta0] (blue2) {$k_{2,i}$};
  \node[obs, left=0.3cm of blue2] (total2) {$n_{2,i}$};

  \node[det, below=2.5cm of alpha0] (alphapost) {$\alpha_{post,i}$};
  \node[det, below=2.5cm of beta0] (betapost) {$\beta_{post,i}$};

  \node[obs, below=1cm of alphapost, xshift=0.75cm] (choice) {$y_i$};

